const cfg = $json || {};
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

const email = typeof cfg.email === 'string' ? cfg.email.trim() : '';
const password = typeof cfg.password === 'string' ? cfg.password : '';
const totpSecret = typeof cfg.totpSecret === 'string' ? cfg.totpSecret.trim() : '';
const apiBase = typeof cfg.apiBase === 'string' ? cfg.apiBase.replace(/\/+$/, '') : '';
const userAgent = typeof cfg.userAgent === 'string' && cfg.userAgent.trim() ? cfg.userAgent.trim() : 'n8n-airbus-mypayslip/1.0';

let maxDocuments = Number(cfg.maxDocuments);
if (!Number.isFinite(maxDocuments)) maxDocuments = NaN;
if (Number.isFinite(maxDocuments)) maxDocuments = Math.trunc(maxDocuments);

const validationErrors = [];
if (!email) validationErrors.push('email fehlt.');
if (!password) validationErrors.push('password fehlt. Setze AIRBUS_MYPAYSLIP_PASSWORD oder trage den Wert im Set-Node ein.');
if (!totpSecret) validationErrors.push('totpSecret fehlt. Setze AIRBUS_MYPAYSLIP_TOTP_SECRET oder trage den Wert im Set-Node ein.');
if (!apiBase) validationErrors.push('apiBase fehlt.');
if (!Number.isInteger(maxDocuments) || maxDocuments < 0) {
  validationErrors.push('maxDocuments muss eine ganze Zahl >= 0 sein.');
}

if (validationErrors.length) {
  return [{
    json: {
      kind: 'error',
      ok: false,
      status: 'validation_error',
      action: 'downloadPayslipsToPaperless',
      message: validationErrors.join(' '),
      totalAvailable: 0,
      unseenAvailable: 0,
      selectedCount: 0,
      results: []
    }
  }];
}

function parseSetCookie(cookieLine) {
  const first = String(cookieLine || '').split(';')[0];
  const idx = first.indexOf('=');
  if (idx === -1) return null;
  return {
    name: first.slice(0, idx).trim(),
    value: first.slice(idx + 1).trim()
  };
}

function extractSetCookies(headers) {
  const raw = headers?.['set-cookie'] ?? headers?.['Set-Cookie'];
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [String(raw)];
}

function applySetCookies(jar, headers) {
  for (const line of extractSetCookies(headers)) {
    const parsed = parseSetCookie(line);
    if (parsed) jar[parsed.name] = parsed.value;
  }
}

function shortText(value) {
  return String(value == null ? '' : value)
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 260);
}

function cookieHeader(jar) {
  return Object.entries(jar)
    .filter(([, value]) => value != null && value !== '')
    .map(([name, value]) => `${name}=${value}`)
    .join('; ');
}

function toJsonIfPossible(value) {
  if (value == null) return null;
  if (typeof value === 'object' && !Buffer.isBuffer(value) && !(value instanceof Uint8Array)) return value;
  const text = Buffer.isBuffer(value) ? value.toString('utf8') : String(value);
  if (!text.trim()) return null;
  try {
    return JSON.parse(text);
  } catch (error) {
    return null;
  }
}

function getResponseStatus(response) {
  return Number(response?.statusCode || response?.status || 0);
}

function getResponseText(response) {
  const body = response?.body ?? response?.text;
  if (body == null) return '';
  if (Buffer.isBuffer(body)) return body.toString('utf8');
  if (typeof body === 'string') return body;
  if (typeof body === 'object') return JSON.stringify(body);
  return String(body);
}

function ensureHttpOk(response, label) {
  const status = getResponseStatus(response);
  if (!Number.isFinite(status) || status < 200 || status >= 300) {
    throw new Error(`${label} fehlgeschlagen: HTTP ${status}. Antwort: ${shortText(getResponseText(response))}`);
  }
}

async function requestJson({ method, url, body, jar }) {
  const headers = {
    Accept: 'application/json, text/plain, */*',
    'User-Agent': userAgent
  };

  const cookie = cookieHeader(jar);
  if (cookie) headers.Cookie = cookie;

  const options = {
    method,
    url,
    headers,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };

  if (body !== undefined) {
    headers['Content-Type'] = 'application/json';
    options.body = JSON.stringify(body);
  }

  const response = await httpRequest(options);
  applySetCookies(jar, response.headers);
  return {
    status: getResponseStatus(response),
    headers: response.headers || {},
    body: response.body,
    text: getResponseText(response),
    json: toJsonIfPossible(response.body)
  };
}

async function requestBinary({ url, jar }) {
  const headers = {
    Accept: 'application/octet-stream, application/pdf, */*',
    'User-Agent': userAgent
  };

  const cookie = cookieHeader(jar);
  if (cookie) headers.Cookie = cookie;

  const response = await httpRequest({
    method: 'GET',
    url,
    headers,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    encoding: null
  });

  applySetCookies(jar, response.headers);

  let body = response.body;
  if (!Buffer.isBuffer(body)) {
    if (body instanceof Uint8Array) {
      body = Buffer.from(body);
    } else if (typeof body === 'string') {
      body = Buffer.from(body, 'binary');
    } else if (body == null) {
      body = Buffer.from('');
    } else {
      body = Buffer.from(body);
    }
  }

  return {
    status: getResponseStatus(response),
    headers: response.headers || {},
    body
  };
}

function base32ToBytes(input) {
  const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
  const cleaned = String(input || '').toUpperCase().replace(/[^A-Z2-7]/g, '');
  let bits = '';

  for (const char of cleaned) {
    const index = alphabet.indexOf(char);
    if (index === -1) continue;
    bits += index.toString(2).padStart(5, '0');
  }

  const bytes = [];
  for (let i = 0; i + 8 <= bits.length; i += 8) {
    bytes.push(parseInt(bits.slice(i, i + 8), 2));
  }

  return Uint8Array.from(bytes);
}

async function generateTotp(secret) {
  const secretBytes = base32ToBytes(secret);
  if (!secretBytes.length) {
    throw new Error('TOTP-Secret ist leer oder kein gueltiges Base32-Secret.');
  }

  const subtle = globalThis.crypto?.subtle;
  if (!subtle) {
    throw new Error('WebCrypto ist in diesem n8n-Code-Node nicht verfuegbar.');
  }

  const counter = Math.floor(Date.now() / 1000 / 30);
  const msg = new Uint8Array(8);
  let value = counter;
  for (let i = 7; i >= 0; i--) {
    msg[i] = value & 0xff;
    value = Math.floor(value / 256);
  }

  const key = await subtle.importKey('raw', secretBytes, { name: 'HMAC', hash: 'SHA-1' }, false, ['sign']);
  const signature = new Uint8Array(await subtle.sign('HMAC', key, msg));
  const offset = signature[signature.length - 1] & 0x0f;
  const binary = ((signature[offset] & 0x7f) << 24) | ((signature[offset + 1] & 0xff) << 16) | ((signature[offset + 2] & 0xff) << 8) | (signature[offset + 3] & 0xff);
  return String(binary % 1000000).padStart(6, '0');
}

function safeFilePart(value) {
  return String(value || '')
    .replace(/[\/:*?"<>|]+/g, '-')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractHeader(headers, name) {
  const wanted = String(name || '').toLowerCase();
  for (const [key, value] of Object.entries(headers || {})) {
    if (String(key).toLowerCase() === wanted) return Array.isArray(value) ? value[0] : value;
  }
  return '';
}

function filenameFromDisposition(headers) {
  const contentDisposition = String(extractHeader(headers, 'content-disposition') || '');
  if (!contentDisposition) return '';

  const utf8Match = contentDisposition.match(/filename\*=UTF-8''([^;]+)/i);
  if (utf8Match) {
    try {
      return decodeURIComponent(utf8Match[1]).trim();
    } catch (error) {
      return utf8Match[1].trim();
    }
  }

  const plainMatch = contentDisposition.match(/filename="?([^";]+)"?/i);
  return plainMatch ? plainMatch[1].trim() : '';
}

function extensionFromMimeType(mimeType) {
  const normalized = String(mimeType || '').toLowerCase();
  if (normalized.includes('pdf')) return 'pdf';
  if (normalized.includes('png')) return 'png';
  if (normalized.includes('jpeg') || normalized.includes('jpg')) return 'jpg';
  return 'bin';
}

function fallbackFilename(doc, headers) {
  const preferredName = safeFilePart(doc.name || '');
  const contentType = String(extractHeader(headers, 'content-type') || '');
  const ext = extensionFromMimeType(contentType);
  if (preferredName && /\.[A-Za-z0-9]{2,5}$/.test(preferredName)) return preferredName;
  if (preferredName) return `${preferredName}.${ext}`;
  return `airbus-payslip-${safeFilePart(doc.documentId || doc.itemId || 'document')}.${ext}`;
}

function getStaticData() {
  if (typeof getWorkflowStaticData === 'function') return getWorkflowStaticData('global');
  if (typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('workflow static data ist in diesem Kontext nicht verfuegbar.');
}

const jar = {};
const loginUrl = `${apiBase}/Account/Login`;
const twoFactorUrl = `${apiBase}/Account/TwoFactor/Login`;
const documentsUrl = `${apiBase}/Document`;

const loginResponse = await requestJson({
  method: 'POST',
  url: loginUrl,
  body: {
    loginName: email,
    password
  },
  jar
});
ensureHttpOk(loginResponse, 'Login');

const totpToken = await generateTotp(totpSecret);
const twoFactorResponse = await requestJson({
  method: 'POST',
  url: twoFactorUrl,
  body: { token: totpToken },
  jar
});
ensureHttpOk(twoFactorResponse, 'TOTP-Login');

const documentsResponse = await requestJson({
  method: 'GET',
  url: documentsUrl,
  jar
});
ensureHttpOk(documentsResponse, 'Dokumentenliste laden');

const rawDocuments = Array.isArray(documentsResponse.json)
  ? documentsResponse.json
  : Array.isArray(documentsResponse.json?.data)
    ? documentsResponse.json.data
    : Array.isArray(documentsResponse.json?.results)
      ? documentsResponse.json.results
      : [];

const documents = rawDocuments
  .filter((doc) => doc && doc.itemId != null && doc.documentId != null)
  .slice()
  .sort((a, b) => {
    const left = new Date(b?.insertTime || 0).getTime();
    const right = new Date(a?.insertTime || 0).getTime();
    return left - right;
  });

const staticData = getStaticData.call(this);
if (!staticData.processedDocumentIds || typeof staticData.processedDocumentIds !== 'object') {
  staticData.processedDocumentIds = {};
}
const processedDocumentIds = staticData.processedDocumentIds;

const unseenDocuments = documents.filter((doc) => !processedDocumentIds[String(doc.documentId)]);
const selectedDocuments = maxDocuments === 0 ? unseenDocuments : unseenDocuments.slice(0, maxDocuments);

if (selectedDocuments.length === 0) {
  return [{
    json: {
      kind: 'noop',
      ok: true,
      status: 'nothing_new',
      action: 'downloadPayslipsToPaperless',
      message: 'Keine neuen Dokumente gefunden.',
      totalAvailable: documents.length,
      unseenAvailable: unseenDocuments.length,
      selectedCount: 0,
      results: []
    }
  }];
}

const output = [];
for (const doc of selectedDocuments) {
  const downloadUrl = `${documentsUrl}/${encodeURIComponent(String(doc.itemId))}/${encodeURIComponent(String(doc.documentId))}`;
  const downloadResponse = await requestBinary({ url: downloadUrl, jar });
  ensureHttpOk(downloadResponse, `Dokument ${doc.documentId} herunterladen`);

  const fileName = filenameFromDisposition(downloadResponse.headers) || fallbackFilename(doc, downloadResponse.headers);
  const mimeType = String(extractHeader(downloadResponse.headers, 'content-type') || 'application/octet-stream').split(';')[0].trim() || 'application/octet-stream';

  output.push({
    json: {
      kind: 'document',
      ok: true,
      status: 'downloaded',
      action: 'downloadPayslipsToPaperless',
      totalAvailable: documents.length,
      unseenAvailable: unseenDocuments.length,
      selectedCount: selectedDocuments.length,
      email,
      maxDocuments,
      itemId: String(doc.itemId),
      documentId: String(doc.documentId),
      documentName: doc.name || null,
      insertTime: doc.insertTime || null,
      isNew: doc.isNew === true,
      customFields: Array.isArray(doc.customFields) ? doc.customFields : [],
      fileName
    },
    binary: {
      data: {
        data: downloadResponse.body.toString('base64'),
        fileName,
        mimeType
      }
    }
  });
}

return output;

const source = $('Fetch and download selected documents').item.json || {};
const upload = $json || {};

const success = upload.isSuccess === true || upload.status === 'success';

return [{
  json: {
    kind: 'result',
    ok: success,
    status: success ? 'uploaded' : 'failed',
    action: 'downloadPayslipsToPaperless',
    documentId: source.documentId || null,
    itemId: source.itemId || null,
    filename: source.fileName || upload.filename || null,
    documentName: source.documentName || null,
    insertTime: source.insertTime || null,
    customFields: source.customFields || [],
    totalAvailable: source.totalAvailable || 0,
    unseenAvailable: source.unseenAvailable || 0,
    selectedCount: source.selectedCount || 0,
    paperless: upload,
    errorReason: success ? null : (upload.errorReason || upload.message || 'paperless_upload_failed')
  }
}];

const row = $json || {};

function getStaticData() {
  if (typeof getWorkflowStaticData === 'function') return getWorkflowStaticData('global');
  if (typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('workflow static data ist in diesem Kontext nicht verfuegbar.');
}

const staticData = getStaticData.call(this);
if (!staticData.processedDocumentIds || typeof staticData.processedDocumentIds !== 'object') {
  staticData.processedDocumentIds = {};
}

if (row.status === 'uploaded' && row.documentId) {
  staticData.processedDocumentIds[String(row.documentId)] = new Date().toISOString();
}

const entries = Object.entries(staticData.processedDocumentIds);
if (entries.length > 500) {
  entries.sort((a, b) => new Date(b[1]).getTime() - new Date(a[1]).getTime());
  staticData.processedDocumentIds = Object.fromEntries(entries.slice(0, 500));
}

return [{ json: row }];

const rows = $input.all().map((item) => item.json || {});

const uploadedCount = rows.filter((row) => row.status === 'uploaded').length;
const failedCount = rows.filter((row) => row.status === 'failed').length;
const totalAvailable = rows[0]?.totalAvailable || 0;
const unseenAvailable = rows[0]?.unseenAvailable || 0;
const selectedCount = rows[0]?.selectedCount || rows.length;

return [{
  json: {
    ok: failedCount === 0,
    status: failedCount === 0 ? 'success' : 'partial_failure',
    action: 'downloadPayslipsToPaperless',
    message: failedCount === 0
      ? `${uploadedCount} Dokument(e) erfolgreich an Paperless uebergeben.`
      : `${uploadedCount} Dokument(e) erfolgreich, ${failedCount} fehlgeschlagen.`,
    totalAvailable,
    unseenAvailable,
    selectedCount,
    uploadedCount,
    failedCount,
    results: rows.map((row) => ({
      documentId: row.documentId || null,
      itemId: row.itemId || null,
      filename: row.filename || null,
      status: row.status || null,
      errorReason: row.errorReason || null
    }))
  }
}];

const data = $json || {};

return [{
  json: {
    ok: data.ok !== false,
    status: data.status || data.kind || 'noop',
    action: data.action || 'downloadPayslipsToPaperless',
    message: data.message || null,
    totalAvailable: data.totalAvailable || 0,
    unseenAvailable: data.unseenAvailable || 0,
    selectedCount: data.selectedCount || 0,
    uploadedCount: 0,
    failedCount: data.ok === false ? 1 : 0,
    results: Array.isArray(data.results) ? data.results : []
  }
}];
